function SplitDiff({ original, modified, fileName }) {
  const { div, span, pre } = tags;

  const computeDiff = () => {
    const origLines = original.split('\n');
    const modLines = modified.split('\n');
    const maxLines = Math.max(origLines.length, modLines.length);
    const diff = [];

    for (let i = 0; i < maxLines; i++) {
      const orig = origLines[i] || '';
      const mod = modLines[i] || '';
      const type = orig === mod ? 'same' : !origLines[i] ? 'add' : !modLines[i] ? 'del' : 'change';
      diff.push({ lineNum: i + 1, orig, mod, type });
    }
    return diff;
  };

  const typeStyles = {
    same: '',
    add: '_bg[#002200]',
    del: '_bg[#220000]',
    change: '_bg[#222200]'
  };

  return div({ class: css('term-panel _flex _col _hfull') },
    div({ class: css('_flex _aic _jcsb _p2 _borderB _bordercolor[#333]') },
      span({ class: css('_fontbold') }, fileName || 'Diff'),
      div({ class: css('_flex _aic _gap2 _textsm') },
        span({ class: css('_fggreen') }, `+${computeDiff().filter(d => d.type === 'add').length}`),
        span({ class: css('_fgred') }, `-${computeDiff().filter(d => d.type === 'del').length}`)
      )
    ),
    div({ class: css('_grid _flex1 _overflow[auto]'), style: 'grid-template-columns: 1fr 1fr' },
      pre({ class: css('_m0 _p2 _borderR _bordercolor[#333] _overflow[auto]') },
        ...computeDiff().map(line =>
          div({ class: css(`_flex ${typeStyles[line.type]}`) },
            span({ class: css('_w[40px] _fgmuted _textright _pr2 _select[none]') }, line.lineNum),
            span({ class: line.type === 'del' ? css('term-diff-del') : '' }, line.orig || ' ')
          )
        )
      ),
      pre({ class: css('_m0 _p2 _overflow[auto]') },
        ...computeDiff().map(line =>
          div({ class: css(`_flex ${typeStyles[line.type]}`) },
            span({ class: css('_w[40px] _fgmuted _textright _pr2 _select[none]') }, line.lineNum),
            span({ class: line.type === 'add' ? css('term-diff-add') : '' }, line.mod || ' ')
          )
        )
      )
    )
  );
}

function UnifiedDiff({ diff, fileName }) {
  const { div, span, pre } = tags;

  const parseUnified = (text) => {
    return text.split('\n').map((line, i) => {
      let type = 'context';
      if (line.startsWith('+')) type = 'add';
      else if (line.startsWith('-')) type = 'del';
      else if (line.startsWith('@')) type = 'hunk';
      return { num: i + 1, text: line, type };
    });
  };

  const lines = parseUnified(diff);
  const lineStyles = {
    add: '_bg[#002200] _fggreen',
    del: '_bg[#220000] _fgred',
    hunk: '_fgcyan _bgmuted/10',
    context: ''
  };

  return div({ class: css('term-panel _flex _col _hfull') },
    div({ class: css('_p2 _borderB _bordercolor[#333] _fontbold') }, fileName || 'Diff'),
    pre({ class: css('_m0 _p2 _flex1 _overflow[auto]') },
      ...lines.map(line =>
        div({ class: css(`_flex ${lineStyles[line.type]}`) },
          span({ class: css('_w[40px] _fgmuted _textright _pr2 _select[none]') },
            line.type === 'hunk' ? '' : line.num
          ),
          span({}, line.text)
        )
      )
    )
  );
}

function InlineDiff({ original, modified }) {
  const { div, span, del, ins } = tags;
  // Simple word-level diff (production would use proper diff algorithm)
  const origWords = original.split(' ');
  const modWords = modified.split(' ');

  const result = [];
  let i = 0, j = 0;
  while (i < origWords.length || j < modWords.length) {
    if (origWords[i] === modWords[j]) {
      result.push({ type: 'same', text: origWords[i] });
      i++; j++;
    } else if (!modWords.includes(origWords[i])) {
      result.push({ type: 'del', text: origWords[i] });
      i++;
    } else {
      result.push({ type: 'add', text: modWords[j] });
      j++;
    }
  }

  return div({ class: css('term-panel _p2') },
    ...result.map(w => {
      if (w.type === 'del') return del({ class: css('_bg[#330000] _fgred _line-through') }, w.text + ' ');
      if (w.type === 'add') return ins({ class: css('_bg[#003300] _fggreen _no-underline') }, w.text + ' ');
      return span({}, w.text + ' ');
    })
  );
}

function DiffView({ variant = 'split', ...props }) {
  switch (variant) {
    case 'unified': return UnifiedDiff(props);
    case 'inline': return InlineDiff(props);
    default: return SplitDiff(props);
  }
}
